class DatabaseConnection:
    def connect(self):
        raise NotImplementedError

class MySQLConnection(DatabaseConnection):
    def connect(self):
        return "MySQL connected"

class PostgreSQLConnection(DatabaseConnection):
    def connect(self):
        return "PostgreSQL connected"

class ConnectionFactory:
    @staticmethod
    def create(db_type: str) -> DatabaseConnection:
        if db_type == "mysql":
            return MySQLConnection()
        elif db_type == "postgresql":
            return PostgreSQLConnection()
        raise ValueError(f"Unknown db type: {db_type}")

class EventListener:
    def on_event(self, event_type: str, data: dict):
        pass

class EventBus:
    def __init__(self):
        self._listeners: dict[str, list[EventListener]] = {}

    def subscribe(self, event_type: str, listener: EventListener):
        if event_type not in self._listeners:
            self._listeners[event_type] = []
        self._listeners[event_type].append(listener)

    def unsubscribe(self, event_type: str, listener: EventListener):
        self._listeners[event_type].remove(listener)

    def publish(self, event_type: str, data: dict):
        for listener in self._listeners.get(event_type, []):
            listener.on_event(event_type, data)

class PaymentStrategy:
    def pay(self, amount: float) -> str:
        raise NotImplementedError

class AlipayStrategy(PaymentStrategy):
    def pay(self, amount: float) -> str:
        return f"Alipay: {amount}"

class WechatStrategy(PaymentStrategy):
    def pay(self, amount: float) -> str:
        return f"Wechat: {amount}"

class PaymentContext:
    def __init__(self, strategy: PaymentStrategy):
        self._strategy = strategy

    def execute_payment(self, amount: float) -> str:
        return self._strategy.pay(amount)

class ConfigManager:
    _instance = None

    def __new__(cls):
        if cls._instance is None:
            cls._instance = super().__new__(cls)
            cls._instance._config = {}
        return cls._instance

    def get(self, key: str, default=None):
        return self._config.get(key, default)

    def set(self, key: str, value):
        self._config[key] = value

# Usage
config1 = ConfigManager()
config2 = ConfigManager()
assert config1 is config2

from functools import wraps
import logging

def log_execution(func):
    @wraps(func)
    def wrapper(*args, **kwargs):
        logging.info(f"Calling {func.__name__}")
        result = func(*args, **kwargs)
        logging.info(f"Called {func.__name__}")
        return result
    return wrapper

@log_execution
def process_order(order_id: str):
    return f"Order {order_id} processed"

class LoggingMixin:
    def log_method(self, method):
        @wraps(method)
        def wrapper(*args, **kwargs):
            self.logger.info(f"{method.__name__} called")
            return method(*args, **kwargs)
        return wrapper
